app/globals.css:
@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;1,300;1,400;1,500&family=DM+Sans:wght@300;400;500&display=swap');
@import "tailwindcss";

/* ─── Design Tokens ──────────────────────────────────────────────────────── */
:root {
  /* Warm Minimalist Palette */
  --cream:      #F5F0E8;
  --parchment:  #EDE5D4;
  --linen:      #E8DFC9;
  --taupe:      #C4B49A;
  --sand:       #A89880;
  --terracotta: #C4754A;
  --amber:      #B8843A;
  --charcoal:   #2C2926;
  --ink:        #1A1714;
  --warm-grey:  #8C8078;
  --olive:      #7A8B6F;
  --sage:       #A3B18A;
  --blush:      #D4A59A;
  --border:     rgba(164, 148, 124, 0.25);
  --border-dark: rgba(44, 41, 38, 0.12);

  --background: var(--cream);
  --foreground: var(--charcoal);

  /* Typography */
  --font-serif: 'Cormorant Garamond', Georgia, serif;
  --font-sans:  'DM Sans', system-ui, sans-serif;

  /* Spacing */
  --section-pad: 8rem 5rem;
  --section-pad-sm: 5rem 2rem;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: 'DM Sans', sans-serif;
}

/* ─── Reset ──────────────────────────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { scroll-behavior: smooth; font-size: 16px; }

body {
  background: var(--cream);
  color: var(--charcoal);
  font-family: var(--font-sans);
  font-weight: 300;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  letter-spacing: 0.01em;
}

body.quickview-open { overflow: hidden; }

img { display: block; }

/* Scrollbar */
::-webkit-scrollbar { width: 5px; }
::-webkit-scrollbar-track { background: var(--cream); }
::-webkit-scrollbar-thumb { background: var(--taupe); border-radius: 0; }

/* ─── Typography Utilities ───────────────────────────────────────────────── */
.serif { font-family: var(--font-serif); }

/* ─── Global Animations ──────────────────────────────────────────────────── */
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(24px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes fadeIn {
  from { opacity: 0; }
  to   { opacity: 1; }
}
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(40px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes float {
  0%, 100% { transform: translateY(0); }
  50%      { transform: translateY(-12px); }
}
@keyframes slideInRight {
  from { transform: translateX(100%); }
  to   { transform: translateX(0); }
}
@keyframes slideOutRight {
  from { transform: translateX(0); }
  to   { transform: translateX(100%); }
}
@keyframes fadeInBackdrop {
  from { opacity: 0; }
  to   { opacity: 1; }
}
@keyframes marquee {
  from { transform: translateX(0); }
  to   { transform: translateX(-50%); }
}
@keyframes pulseGlow {
  0%, 100% { box-shadow: 0 0 0 0 rgba(196, 117, 74, 0.3); }
  50%      { box-shadow: 0 0 0 8px rgba(196, 117, 74, 0); }
}

/* ─── Navbar ─────────────────────────────────────────────────────────────── */
.navbar {
  position: fixed;
  top: 0; left: 0; right: 0;
  z-index: 200;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 4rem;
  height: 76px;
  background: rgba(245, 240, 232, 0.88);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-bottom: 1px solid var(--border-dark);
  transition: background 0.4s ease;
}
.navbar-logo {
  font-family: var(--font-serif);
  font-size: 1.6rem;
  font-weight: 400;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--ink);
  text-decoration: none;
}
.navbar-logo span {
  font-style: italic;
  font-weight: 300;
  color: var(--amber);
}
.navbar-links {
  display: flex;
  gap: 3rem;
  list-style: none;
}
.navbar-links a {
  font-size: 0.78rem;
  font-weight: 400;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--warm-grey);
  text-decoration: none;
  transition: color 0.25s ease;
  position: relative;
}
.navbar-links a::after {
  content: '';
  position: absolute;
  bottom: -4px; left: 0;
  width: 0; height: 1px;
  background: var(--terracotta);
  transition: width 0.3s ease;
}
.navbar-links a:hover { color: var(--ink); }
.navbar-links a:hover::after { width: 100%; }
.navbar-actions { display: flex; align-items: center; gap: 1.5rem; }
.navbar-cart {
  font-size: 0.78rem;
  font-weight: 400;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--ink);
  background: none;
  border: 1px solid var(--charcoal);
  padding: 0.55rem 1.4rem;
  cursor: pointer;
  transition: all 0.25s ease;
}
.navbar-cart:hover { background: var(--charcoal); color: var(--cream); }

/* ─── Hero ───────────────────────────────────────────────────────────────── */
.hero-section {
  position: relative;
  width: 100%;
  height: 100svh;
  min-height: 640px;
  overflow: hidden;
  display: grid;
  grid-template-columns: 1fr 1fr;
}

/* Left editorial panel */
.hero-editorial {
  position: relative;
  z-index: 10;
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 0 5rem;
  background: var(--cream);
}
.hero-eyebrow {
  font-size: 0.72rem;
  font-weight: 400;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  color: var(--amber);
  margin-bottom: 1.5rem;
  opacity: 0;
  animation: fadeUp 0.9s forwards 0.3s;
}
.hero-title {
  font-family: var(--font-serif);
  font-size: clamp(3.2rem, 5.5vw, 6rem);
  font-weight: 300;
  line-height: 1.0;
  letter-spacing: -0.01em;
  color: var(--ink);
  margin-bottom: 2rem;
  opacity: 0;
  animation: fadeUp 0.9s forwards 0.5s;
}
.hero-title em {
  font-style: italic;
  font-weight: 300;
  color: var(--terracotta);
}
.hero-sub {
  font-size: 0.92rem;
  font-weight: 300;
  color: var(--warm-grey);
  max-width: 360px;
  line-height: 1.8;
  margin-bottom: 3rem;
  opacity: 0;
  animation: fadeUp 0.9s forwards 0.7s;
}
.hero-actions {
  display: flex;
  align-items: center;
  gap: 2rem;
  opacity: 0;
  animation: fadeUp 0.9s forwards 0.9s;
}
.hero-scroll-hint {
  position: absolute;
  bottom: 5rem;
  right: 4rem;
  z-index: 10;
  display: flex;
  align-items: center;
  gap: 1rem;
  font-size: 0.68rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--warm-grey);
  opacity: 0;
  animation: fadeUp 0.9s forwards 1.2s;
}
.hero-scroll-line {
  width: 48px;
  height: 1px;
  background: var(--taupe);
}
.hero-float-badge {
  position: absolute;
  bottom: 10rem; left: 3rem;
  z-index: 20;
  background: rgba(245, 240, 232, 0.92);
  backdrop-filter: blur(12px);
  padding: 1rem 1.5rem;
  border: 1px solid var(--border);
  display: flex;
  align-items: center;
  gap: 0.8rem;
  animation: float 4s ease-in-out infinite, fadeUp 0.9s forwards 1.4s;
  opacity: 0;
}
.hero-float-badge .badge-icon { font-size: 1.2rem; }
.hero-float-badge .badge-text {
  font-size: 0.7rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--charcoal);
  font-weight: 400;
}

/* Right image panel */
.hero-image-panel {
  position: relative;
  overflow: hidden;
}
.hero-slides { position: absolute; inset: 0; }
.hero-slide {
  position: absolute; inset: 0;
  opacity: 0;
  transition: opacity 1.2s cubic-bezier(0.4, 0, 0.2, 1);
}
.hero-slide.active { opacity: 1; }
.hero-img { object-fit: cover; transition: transform 10s ease-out; }
.hero-slide.active .hero-img { transform: scale(1.04); }
.hero-overlay {
  position: absolute; inset: 0;
  background: linear-gradient(to right, rgba(245,240,232,0.15) 0%, transparent 30%);
}
.hero-dots {
  position: absolute;
  bottom: 2.5rem; left: 2.5rem;
  z-index: 10;
  display: flex; flex-direction: column; gap: 0.6rem;
}
.hero-dot {
  width: 2px; height: 24px;
  border: none; background: rgba(255,255,255,0.35);
  cursor: pointer;
  transition: all 0.4s ease; padding: 0;
}
.hero-dot.active { background: #fff; height: 40px; }

/* ─── Buttons ────────────────────────────────────────────────────────────── */
.btn-primary {
  display: inline-flex;
  align-items: center;
  gap: 0.6rem;
  padding: 0.85rem 2.5rem;
  background: var(--charcoal);
  color: var(--cream);
  font-family: var(--font-sans);
  font-size: 0.78rem;
  font-weight: 400;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  text-decoration: none;
  border: 1px solid var(--charcoal);
  cursor: pointer;
  transition: all 0.3s ease;
}
.btn-primary:hover {
  background: var(--ink);
  border-color: var(--ink);
  transform: translateY(-1px);
}
.btn-primary:active { transform: translateY(0); }
.btn-ghost {
  display: inline-flex;
  align-items: center;
  font-size: 0.78rem;
  font-weight: 400;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--warm-grey);
  text-decoration: none;
  border-bottom: 1px solid transparent;
  padding-bottom: 2px;
  transition: all 0.25s ease;
}
.btn-ghost:hover { color: var(--charcoal); border-color: var(--charcoal); }

/* ─── Marquee ────────────────────────────────────────────────────────────── */
.marquee-section {
  background: var(--charcoal);
  overflow: hidden;
  padding: 1rem 0;
}
.marquee-track {
  display: flex;
  white-space: nowrap;
  animation: marquee 32s linear infinite;
}
.marquee-item {
  display: inline-flex;
  align-items: center;
  gap: 2rem;
  padding: 0 2.5rem;
  font-size: 0.72rem;
  font-weight: 400;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: rgba(245, 240, 232, 0.7);
}
.marquee-dot {
  width: 3px; height: 3px;
  border-radius: 50%;
  background: var(--amber);
}

/* ─── Section Header ─────────────────────────────────────────────────────── */
.section-eyebrow {
  font-size: 0.7rem;
  font-weight: 400;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  color: var(--amber);
  margin-bottom: 1rem;
}
.section-title {
  font-family: var(--font-serif);
  font-size: clamp(2.2rem, 4vw, 3.6rem);
  font-weight: 300;
  letter-spacing: -0.01em;
  color: var(--ink);
  line-height: 1.1;
}
.section-title em { font-style: italic; color: var(--terracotta); font-weight: 300; }
.section-sub {
  font-size: 0.92rem;
  font-weight: 300;
  color: var(--warm-grey);
  line-height: 1.85;
  max-width: 480px;
}

/* ─── Botanical Divider ──────────────────────────────────────────────────── */
.botanical-divider {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 1.5rem;
  padding: 3rem 0;
}
.botanical-divider .divider-line {
  width: 80px; height: 1px;
  background: var(--border-dark);
}
.botanical-divider .divider-icon {
  font-size: 1.2rem;
  color: var(--taupe);
  animation: float 5s ease-in-out infinite;
}

/* ─── Collection Section ─────────────────────────────────────────────────── */
.collection-section {
  padding: 9rem 5rem 7rem;
  background: var(--cream);
}
.collection-header {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 3rem;
  margin-bottom: 1.5rem;
  flex-wrap: wrap;
}
.collection-divider {
  width: 100%;
  height: 1px;
  background: var(--border-dark);
  margin-bottom: 4rem;
}
.collection-filters {
  display: flex;
  gap: 0rem;
}
.filter-chip {
  font-size: 0.72rem;
  font-weight: 400;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  padding: 0.5rem 1.5rem;
  border: 1px solid var(--border-dark);
  border-left: none;
  color: var(--warm-grey);
  background: transparent;
  cursor: pointer;
  transition: all 0.25s ease;
}
.filter-chip:first-child { border-left: 1px solid var(--border-dark); }
.filter-chip:hover,
.filter-chip.active {
  background: var(--charcoal);
  color: var(--cream);
  border-color: var(--charcoal);
}
.filter-chip.active + .filter-chip { border-left: none; }

/* ─── Product Grid ───────────────────────────────────────────────────────── */
.product-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 0;
}

.product-card {
  position: relative;
  display: flex;
  flex-direction: column;
  border: 1px solid var(--border-dark);
  border-right: none;
  transition: background 0.3s ease;
  background: var(--cream);
}
.product-card:nth-child(3n) { border-right: 1px solid var(--border-dark); }
.product-card:nth-child(n+4) { border-top: none; }
.product-card:hover { background: var(--parchment); }

.product-tag {
  position: absolute;
  top: 1.2rem; left: 1.2rem;
  z-index: 10;
  font-size: 0.65rem;
  font-weight: 400;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  background: var(--charcoal);
  color: var(--cream);
  padding: 0.3rem 0.8rem;
}
.product-img-wrap {
  position: relative;
  width: 100%;
  aspect-ratio: 3 / 4;
  overflow: hidden;
  cursor: pointer;
  background: var(--parchment);
}
.product-img {
  object-fit: cover;
  transition: transform 0.9s cubic-bezier(0.4, 0, 0.2, 1);
  animation: fadeIn 0.5s ease;
}
.product-card:hover .product-img { transform: scale(1.04); }
.product-img-hint {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0.8rem;
  background: rgba(44, 41, 38, 0.45);
  color: var(--cream);
  font-size: 0.7rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.35s ease;
}
.product-img-wrap:hover .product-img-hint { opacity: 1; pointer-events: auto; }

.product-quickview-btn {
  font-size: 0.68rem;
  font-weight: 400;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  padding: 0.5rem 1.3rem;
  border: 1px solid rgba(255,255,255,0.7);
  color: var(--cream);
  background: rgba(44, 41, 38, 0.3);
  backdrop-filter: blur(4px);
  cursor: pointer;
  transition: all 0.25s ease;
}
.product-quickview-btn:hover {
  background: var(--cream);
  color: var(--charcoal);
  border-color: var(--cream);
}

.product-img-dots {
  position: absolute;
  bottom: 1.2rem; left: 50%;
  transform: translateX(-50%);
  display: flex; gap: 6px; z-index: 5;
}
.product-img-dot {
  width: 5px; height: 5px;
  border-radius: 50%;
  background: rgba(255,255,255,0.5);
  transition: all 0.25s;
}
.product-img-dot.active { background: #fff; transform: scale(1.3); }

.product-info {
  padding: 1.75rem 1.75rem 2rem;
  display: flex;
  flex-direction: column;
  gap: 0.6rem;
  flex: 1;
}
.product-number {
  font-size: 0.65rem;
  letter-spacing: 0.2em;
  color: var(--taupe);
  margin-bottom: 0.3rem;
}
.product-name {
  font-family: var(--font-serif);
  font-size: 1.3rem;
  font-weight: 400;
  color: var(--ink);
  line-height: 1.2;
}
.product-scent {
  font-size: 0.82rem;
  font-weight: 300;
  color: var(--warm-grey);
  letter-spacing: 0.04em;
}
.product-bottom {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: 1.5rem;
  padding-top: 1.25rem;
  border-top: 1px solid var(--border-dark);
}
.product-price {
  font-family: var(--font-serif);
  font-size: 1.2rem;
  font-weight: 400;
  color: var(--ink);
}
.btn-add {
  font-size: 0.68rem;
  font-weight: 400;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  padding: 0.55rem 1.25rem;
  border: 1px solid var(--charcoal);
  color: var(--charcoal);
  background: transparent;
  cursor: pointer;
  transition: all 0.25s ease;
}
.btn-add:hover { background: var(--charcoal); color: var(--cream); }

/* ─── Quick View Panel ───────────────────────────────────────────────────── */
.quickview-backdrop {
  position: fixed;
  inset: 0;
  z-index: 900;
  background: rgba(26, 23, 20, 0.55);
  backdrop-filter: blur(6px);
  -webkit-backdrop-filter: blur(6px);
  animation: fadeInBackdrop 0.3s ease forwards;
  cursor: pointer;
}
.quickview-panel {
  position: fixed;
  top: 0; right: 0; bottom: 0;
  z-index: 950;
  width: 520px;
  max-width: 92vw;
  background: var(--cream);
  overflow-y: auto;
  animation: slideInRight 0.45s cubic-bezier(0.16, 1, 0.3, 1) forwards;
  border-left: 1px solid var(--border-dark);
}
.quickview-panel.closing {
  animation: slideOutRight 0.35s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}
.quickview-close {
  position: absolute;
  top: 1.5rem; right: 1.5rem;
  z-index: 10;
  width: 40px; height: 40px;
  display: flex; align-items: center; justify-content: center;
  border: 1px solid var(--border-dark);
  background: var(--cream);
  cursor: pointer;
  font-size: 1rem;
  color: var(--charcoal);
  transition: all 0.2s ease;
}
.quickview-close:hover { background: var(--charcoal); color: var(--cream); }

.quickview-image {
  position: relative;
  width: 100%;
  aspect-ratio: 4 / 5;
  overflow: hidden;
  background: var(--parchment);
}

.quickview-content {
  padding: 2.5rem;
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
}
.quickview-eyebrow {
  font-size: 0.65rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--amber);
}
.quickview-name {
  font-family: var(--font-serif);
  font-size: 2rem;
  font-weight: 300;
  color: var(--ink);
  line-height: 1.1;
}
.quickview-scent {
  font-size: 0.88rem;
  color: var(--warm-grey);
  font-weight: 300;
}
.quickview-desc {
  font-size: 0.88rem;
  color: var(--warm-grey);
  font-weight: 300;
  line-height: 1.8;
  padding-bottom: 1.5rem;
  border-bottom: 1px solid var(--border-dark);
}
.quickview-price {
  font-family: var(--font-serif);
  font-size: 1.6rem;
  font-weight: 400;
  color: var(--ink);
}

/* Color Swatches */
.quickview-label {
  font-size: 0.68rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--charcoal);
  font-weight: 400;
  margin-bottom: 0.6rem;
}
.quickview-colors {
  display: flex;
  gap: 0.7rem;
  flex-wrap: wrap;
}
.color-swatch {
  width: 28px; height: 28px;
  border-radius: 50%;
  border: 2px solid transparent;
  cursor: pointer;
  transition: all 0.25s ease;
  position: relative;
}
.color-swatch::after {
  content: '';
  position: absolute;
  inset: -4px;
  border-radius: 50%;
  border: 2px solid transparent;
  transition: border-color 0.25s ease;
}
.color-swatch:hover::after { border-color: var(--taupe); }
.color-swatch.selected::after { border-color: var(--charcoal); }

/* Occasion Tags */
.quickview-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}
.occasion-tag {
  font-size: 0.68rem;
  font-weight: 400;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  padding: 0.45rem 1rem;
  border: 1px solid var(--border-dark);
  color: var(--warm-grey);
  background: transparent;
  border-radius: 2px;
  cursor: default;
  transition: all 0.25s ease;
}
.occasion-tag:hover {
  border-color: var(--terracotta);
  color: var(--terracotta);
}

.quickview-add {
  width: 100%;
  padding: 1rem;
  background: var(--charcoal);
  color: var(--cream);
  font-family: var(--font-sans);
  font-size: 0.78rem;
  font-weight: 400;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  border: 1px solid var(--charcoal);
  cursor: pointer;
  transition: all 0.3s ease;
  margin-top: 0.5rem;
}
.quickview-add:hover {
  background: var(--ink);
  border-color: var(--ink);
}

/* ─── Features Strip ─────────────────────────────────────────────────────── */
.features-section {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  border-top: 1px solid var(--border-dark);
}
.feature-item {
  padding: 3.5rem 2.5rem;
  border-right: 1px solid var(--border-dark);
  text-align: center;
  transition: background 0.3s ease;
}
.feature-item:last-child { border-right: none; }
.feature-item:hover { background: var(--parchment); }
.feature-icon {
  font-size: 1.4rem;
  margin-bottom: 1rem;
  color: var(--amber);
  display: inline-block;
  transition: transform 0.3s ease;
}
.feature-item:hover .feature-icon { transform: scale(1.15); }
.feature-title {
  font-family: var(--font-serif);
  font-size: 1rem;
  font-weight: 500;
  color: var(--ink);
  margin-bottom: 0.5rem;
}
.feature-desc {
  font-size: 0.8rem;
  font-weight: 300;
  color: var(--warm-grey);
  line-height: 1.7;
  letter-spacing: 0.03em;
}

/* ─── Gift Shop Section ──────────────────────────────────────────────────── */
.giftshop-section {
  padding: 8rem 5rem;
  background: var(--parchment);
  border-top: 1px solid var(--border-dark);
  border-bottom: 1px solid var(--border-dark);
}
.giftshop-header {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 3rem;
  margin-bottom: 1.5rem;
  flex-wrap: wrap;
}
.giftshop-divider {
  width: 100%;
  height: 1px;
  background: var(--border-dark);
  margin-bottom: 4rem;
}
.giftshop-grid {
  display: grid;
  grid-template-columns: 1.2fr 0.8fr;
  gap: 0;
}
.giftshop-featured {
  border: 1px solid var(--border-dark);
  border-right: none;
}
.giftshop-stack {
  display: grid;
  grid-template-rows: 1fr 1fr;
}
.gift-card {
  position: relative;
  display: flex;
  flex-direction: column;
  border: 1px solid var(--border-dark);
  background: var(--cream);
  transition: all 0.35s ease;
  overflow: hidden;
}
.gift-card:hover { background: rgba(245, 240, 232, 0.8); }
.gift-card + .gift-card { border-top: none; }
.gift-card-img-wrap {
  position: relative;
  width: 100%;
  overflow: hidden;
  background: var(--linen);
}
.giftshop-featured .gift-card-img-wrap { aspect-ratio: 4 / 5; }
.giftshop-stack .gift-card-img-wrap { aspect-ratio: 16 / 10; }
.gift-card-img {
  object-fit: cover;
  transition: transform 0.9s cubic-bezier(0.4, 0, 0.2, 1);
}
.gift-card:hover .gift-card-img { transform: scale(1.04); }
.gift-card-tag {
  position: absolute;
  top: 1.2rem; left: 1.2rem;
  z-index: 5;
  font-size: 0.62rem;
  font-weight: 400;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  background: var(--terracotta);
  color: var(--cream);
  padding: 0.3rem 0.8rem;
}
.gift-card-info {
  padding: 1.75rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  flex: 1;
}
.gift-card-name {
  font-family: var(--font-serif);
  font-size: 1.3rem;
  font-weight: 400;
  color: var(--ink);
  line-height: 1.2;
}
.gift-card-desc {
  font-size: 0.82rem;
  font-weight: 300;
  color: var(--warm-grey);
  line-height: 1.6;
}
.gift-card-bottom {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: 1rem;
  padding-top: 1rem;
  border-top: 1px solid var(--border-dark);
}
.gift-card-price {
  font-family: var(--font-serif);
  font-size: 1.15rem;
  font-weight: 400;
  color: var(--ink);
}

/* ─── Floral Section ─────────────────────────────────────────────────────── */
.floral-section {
  padding: 8rem 5rem;
  background: var(--linen);
}
.floral-header {
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  margin-bottom: 4rem;
}
.floral-header .section-sub {
  margin-top: 1.5rem;
  text-align: center;
}
.floral-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 2rem;
}
.floral-card {
  background: var(--cream);
  border-radius: 8px;
  overflow: hidden;
  transition: all 0.4s ease;
  border: 1px solid var(--border-dark);
}
.floral-card:hover {
  transform: translateY(-6px);
  box-shadow: 0 20px 60px rgba(44, 41, 38, 0.08);
}
.floral-card-img-wrap {
  position: relative;
  width: 100%;
  aspect-ratio: 3 / 4;
  overflow: hidden;
  background: var(--linen);
}
.floral-card-img {
  object-fit: cover;
  transition: transform 0.9s cubic-bezier(0.4, 0, 0.2, 1);
  border-radius: 8px 8px 0 0;
}
.floral-card:hover .floral-card-img { transform: scale(1.05); }
.floral-card-info {
  padding: 1.75rem;
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.5rem;
}
.floral-card-botanical {
  font-size: 0.62rem;
  font-style: italic;
  letter-spacing: 0.12em;
  color: var(--olive);
  text-transform: uppercase;
}
.floral-card-name {
  font-family: var(--font-serif);
  font-size: 1.3rem;
  font-weight: 400;
  color: var(--ink);
  line-height: 1.2;
}
.floral-card-desc {
  font-size: 0.82rem;
  font-weight: 300;
  color: var(--warm-grey);
  line-height: 1.6;
  max-width: 260px;
}
.floral-card-bottom {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 1.5rem;
  margin-top: 1rem;
  padding-top: 1rem;
  border-top: 1px solid var(--border-dark);
  width: 100%;
}
.floral-card-price {
  font-family: var(--font-serif);
  font-size: 1.15rem;
  font-weight: 400;
  color: var(--ink);
}
.btn-add-floral {
  font-size: 0.68rem;
  font-weight: 400;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  padding: 0.5rem 1.2rem;
  border: 1px solid var(--olive);
  color: var(--olive);
  background: transparent;
  cursor: pointer;
  transition: all 0.25s ease;
  border-radius: 3px;
}
.btn-add-floral:hover { background: var(--olive); color: var(--cream); }

/* ─── About Section ──────────────────────────────────────────────────────── */
.about-section {
  display: grid;
  grid-template-columns: 1fr 1fr;
  min-height: 600px;
}
.about-img-side { position: relative; overflow: hidden; }
.about-img { object-fit: cover; transition: transform 1.5s ease; }
.about-img-side:hover .about-img { transform: scale(1.04); }
.about-content-side {
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 6rem 6rem;
  background: var(--parchment);
  gap: 2rem;
}
.about-body {
  font-size: 0.95rem;
  font-weight: 300;
  color: var(--warm-grey);
  line-height: 1.9;
}
.about-stat-row {
  display: flex;
  gap: 3rem;
  padding-top: 2rem;
  border-top: 1px solid var(--border-dark);
}
.about-stat-num {
  font-family: var(--font-serif);
  font-size: 2.5rem;
  font-weight: 300;
  color: var(--terracotta);
  line-height: 1;
}
.about-stat-label {
  font-size: 0.72rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--warm-grey);
  margin-top: 0.3rem;
}

/* ─── Footer ─────────────────────────────────────────────────────────────── */
.footer {
  background: var(--ink);
  color: rgba(245, 240, 232, 0.55);
  padding: 6rem 5rem 3rem;
  display: grid;
  grid-template-columns: 2fr 1fr 1fr 1fr;
  gap: 4rem;
  border-top: 1px solid rgba(255,255,255,0.06);
}
.footer-logo {
  font-family: var(--font-serif);
  font-size: 1.5rem;
  font-weight: 400;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--cream);
  margin-bottom: 1.2rem;
}
.footer-logo span { font-style: italic; color: var(--amber); font-weight: 300; }
.footer-desc {
  font-size: 0.85rem;
  font-weight: 300;
  line-height: 1.8;
  max-width: 280px;
  margin-bottom: 2rem;
}
.footer-social {
  display: flex;
  gap: 1.2rem;
}
.footer-social a {
  font-size: 0.7rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: rgba(245,240,232,0.5);
  text-decoration: none;
  transition: color 0.25s;
}
.footer-social a:hover { color: var(--amber); }
.footer-heading {
  font-size: 0.7rem;
  font-weight: 400;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--cream);
  margin-bottom: 1.5rem;
}
.footer-links { list-style: none; display: flex; flex-direction: column; gap: 0.8rem; }
.footer-links a {
  font-size: 0.85rem;
  font-weight: 300;
  color: rgba(245, 240, 232, 0.55);
  text-decoration: none;
  transition: color 0.25s;
}
.footer-links a:hover { color: var(--amber); }
.footer-bottom {
  background: var(--ink);
  border-top: 1px solid rgba(255,255,255,0.06);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1.5rem 5rem;
  font-size: 0.75rem;
  font-weight: 300;
  letter-spacing: 0.1em;
  color: rgba(245, 240, 232, 0.35);
}

/* ─── Responsive ─────────────────────────────────────────────────────────── */
@media (max-width: 1200px) {
  .product-grid { grid-template-columns: repeat(3, 1fr); }
}

@media (max-width: 1024px) {
  .hero-section { grid-template-columns: 1fr; }
  .hero-image-panel { display: none; }
  .hero-editorial { justify-content: center; padding: 0 3rem; min-height: 100svh; }
  .hero-float-badge { display: none; }

  .product-grid { grid-template-columns: repeat(2, 1fr); }
  .product-card { border-right: 1px solid var(--border-dark); }
  .product-card:nth-child(2n) { border-right: 1px solid var(--border-dark); }
  .product-card:nth-child(n+3) { border-top: none; }

  .features-section { grid-template-columns: repeat(2, 1fr); }
  .feature-item:nth-child(2) { border-right: none; }
  .feature-item:nth-child(3) { border-top: 1px solid var(--border-dark); }
  .feature-item:nth-child(4) { border-top: 1px solid var(--border-dark); border-right: none; }

  .about-section { grid-template-columns: 1fr; }
  .about-img-side { min-height: 400px; }
  .about-content-side { padding: 5rem 3rem; }

  .footer { grid-template-columns: 1fr 1fr; padding: 5rem 3rem 2rem; }
  .footer-bottom { padding: 1.5rem 3rem; }

  .collection-section { padding: 7rem 3rem 5rem; }
  .navbar { padding: 0 2rem; }
  .navbar-links { display: none; }

  .giftshop-section { padding: 6rem 3rem; }
  .giftshop-grid { grid-template-columns: 1fr; }
  .giftshop-featured { border-right: 1px solid var(--border-dark); }
  .giftshop-stack .gift-card:first-child { border-top: none; }

  .floral-section { padding: 6rem 3rem; }
  .floral-grid { grid-template-columns: repeat(2, 1fr); }
}

@media (max-width: 640px) {
  .product-grid { grid-template-columns: 1fr; }
  .product-card { border-right: 1px solid var(--border-dark) !important; border-top: none; }
  .product-card:first-child { border-top: 1px solid var(--border-dark); }

  .footer { grid-template-columns: 1fr; padding: 4rem 2rem 2rem; gap: 2.5rem; }
  .footer-bottom { padding: 1.5rem 2rem; flex-direction: column; gap: 0.5rem; }

  .collection-section { padding: 5rem 1.5rem 3rem; }

  .features-section { grid-template-columns: 1fr; }
  .feature-item { border-right: none; border-top: 1px solid var(--border-dark); }
  .feature-item:first-child { border-top: none; }

  .about-content-side { padding: 4rem 2rem; }

  .giftshop-section { padding: 5rem 1.5rem; }
  .giftshop-grid { grid-template-columns: 1fr; }

  .floral-section { padding: 5rem 1.5rem; }
  .floral-grid { grid-template-columns: 1fr; }
  .floral-card:hover { transform: none; }

  .quickview-panel { width: 100%; max-width: 100vw; }
}

